<template> <Transition name="modal-fade"> <div v-if="modelValue" class="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-50" @click.self="closeModal"> <div class="bg-white dark:bg-gray-800 rounded-lg shadow-xl max-w-lg w-full transform transition-all duration-300 ease-out scale-100 opacity-100" aria-modal="true" role="dialog" aria-labelledby="modal-title"> <!-- رأس النافذة المنبثقة --> <div class="flex items-center justify-between p-4 border-b border-gray-200 dark:border-gray-700"> <h3 id="modal-title" class="text-lg font-semibold text-gray-900 dark:text-white"> <slot name="header"> <!-- محتوى الرأس الافتراضي في حال عدم توفير slot --> عنوان النافذة المنبثقة </slot> </h3> <button type="button" class="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 rounded-md p-1" @click="closeModal" aria-label="إغلاق"> <svg class="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"> <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12" /> </svg> </button> </div> <!-- جسم النافذة المنبثقة --> <div class="p-4 text-gray-700 dark:text-gray-300"> <slot> <!-- محتوى الجسم الافتراضي في حال عدم توفير slot --> هنا يأتي محتوى النافذة المنبثقة الخاص بك. </slot> </div> <!-- تذييل النافذة المنبثقة (اختياري) --> <div v-if="$slots.footer" class="flex justify-end p-4 border-t border-gray-200 dark:border-gray-700"> <slot name="footer"></slot> </div> </div> </div> </Transition> </template> <script setup> import { defineProps, defineEmits, watch, onMounted, onUnmounted } from 'vue'; const props = defineProps({ modelValue: { type: Boolean, default: false } }); const emit = defineEmits(['update:modelValue', 'close']); const closeModal = () => { emit('update:modelValue', false); emit('close'); }; const handleEscape = (event) => { if (event.key === 'Escape' && props.modelValue) { closeModal(); } }; // إدارة تمرير الجسم عند فتح/إغلاق النافذة المنبثقة، ومعالجة مفتاح Escape watch(() => props.modelValue, (newValue) => { if (newValue) { document.body.style.overflow = 'hidden'; document.addEventListener('keydown', handleEscape); } else { document.body.style.overflow = ''; document.removeEventListener('keydown', handleEscape); } }, { immediate: true }); onUnmounted(() => { // التأكد من إزالة مستمع الحدث وإعادة تمكين التمرير عند إلغاء تحميل المكون document.removeEventListener('keydown', handleEscape); document.body.style.overflow = ''; }); <
/script> <style scoped> /* أنماط الانتقال لتأثير التلاشي */ .modal-fade-enter-active, .modal-fade-leave-active { transition: opacity 0.3s ease; } .modal-fade-enter-from, .modal-fade-leave-to { opacity: 0; } <
/style>